namespace Bunit;

internal static class NodeListExtensions
{
	internal static IElement? TryQuerySelector(this INodeList nodes, string cssSelector)
	{
		if (nodes.Length == 0 ||
		    nodes[0].Owner?.Context.GetService<ICssSelectorParser>() is not ICssSelectorParser cssParser)
			return null;

		if (cssParser.ParseSelector(cssSelector) is not ISelector selector)
			return null;

		return nodes.QuerySelector(selector);
	}

	internal static IEnumerable<IElement> TryQuerySelectorAll(this INodeList nodes, string cssSelector)
	{
		if (nodes.Length == 0 ||
		    nodes[0].Owner?.Context.GetService<ICssSelectorParser>() is not ICssSelectorParser cssParser)
			return Enumerable.Empty<IElement>();

		if (cssParser.ParseSelector(cssSelector) is not ISelector selector)
			return Enumerable.Empty<IElement>();

		return nodes.QuerySelectorAll(selector);
	}
}

namespace Bunit.ComponentFactories;

internal sealed class InstanceComponentFactory<TComponent> : IComponentFactory
	where TComponent : IComponent
{
	private readonly TComponent instance;
	private int createCount;

	public InstanceComponentFactory(TComponent instance)
		=> this.instance = instance;

	public bool CanCreate(Type componentType)
		=> componentType == typeof(TComponent);

	public IComponent Create(Type componentType)
	{
		if (createCount == 1)
		{
			throw new InvalidOperationException(
				$"The instance object passed to the" +
				$"{nameof(BunitContext.ComponentFactories)}.{nameof(ComponentFactoryCollectionExtensions.Add)}<{typeof(TComponent).Name}>(instance) method can only be used to replace " +
				$"one {typeof(TComponent)} component in the render tree.");
		}

		createCount++;

		return instance;
	}
}

